/**
 * Build Script - Creates both regular and console-friendly versions
 *
 * ⚠️ GENERATED FILES WARNING:
 * The output files (bookmarklet.js, bookmarklet-console.js) are AUTO-GENERATED.
 * DO NOT edit these files directly - changes will be lost on next build.
 *
 * TO MAKE CHANGES:
 * 1. Edit source files in src/ directory
 * 2. Run: node build.js
 * 3. Generated files will be updated automatically
 *
 * ⚠️ CRITICAL: EXPORT/IMPORT STRIPPING
 * When adding new source files, you MUST add export stripping for them below!
 * The build uses regex to remove ES module syntax. If you see "export" in the
 * output, the regex isn't catching your file.
 *
 * Common patterns that need stripping:
 * - export function foo() {}
 * - export const X = 1
 * - export { a, b, c }
 * - export default X
 * - export class Foo {}
 * - import { x } from './file.js'
 *
 * TO TEST: After building, run: npm test
 * The tests will fail if any export/import keywords remain.
 *
 * VERSION MANAGEMENT:
 * - Update version in src/core/engine.js
 * - Run: node build.js (version will be propagated automatically)
 */

import fs from 'fs';

const outfile = 'bookmarklet.js';
const consoleFile = 'bookmarklet-console.js';

// Read version from engine.js (single source of truth)
const engineSource = fs.readFileSync('src/core/engine.js', 'utf8');
const versionMatch = engineSource.match(/export const VERSION = ['"]([^'"]+)['"]/);
const VERSION = versionMatch ? versionMatch[1] : '0.0.0-DEV';

/**
 * Strip ES module syntax from source code
 * This is CRITICAL - any exports/imports left will cause browser errors
 * 
 * @param {string} code - Source code to strip
 * @returns {string} - Code with all ES module syntax removed
 */
function stripModuleSyntax(code) {
  // Remove JSDoc comments that reference imports/exports
  // These become misleading in bundled code
  code = code.replace(/\/\*\*[\s\S]*?@param[\s\S]*?from\s+['"]\.\//g, '/**');
  code = code.replace(/\/\*\*[\s\S]*?@returns[\s\S]*?from\s+['"]\.\//g, '/**');
  
  return code
    // Remove all import statements (various formats, including multi-line)
    .replace(/import\s+[\s\S]*?\s+from\s+['"][^'"]+['"];?/g, '')
    .replace(/import\s+['"][^'"]+['"];?/g, '')  // side-effect imports
    // Remove all export statements (various formats)
    .replace(/export\s+{/g, 'const __export_dummy = {')  // export { a, b }
    .replace(/export\s+default\s+/g, 'const __default_export = ')  // export default
    .replace(/export\s+const\s+/g, 'const ')
    .replace(/export\s+let\s+/g, 'let ')
    .replace(/export\s+var\s+/g, 'var ')
    .replace(/export\s+function\s+/g, 'function ')
    .replace(/export\s+class\s+/g, 'class ')
    .replace(/export\s+async\s+function/g, 'async function')
    // Remove standalone export/import statements (including in comments)
    .replace(/^\s*(import|export)\s.*;?/gm, '')
    // Remove empty lines created by stripping
    .replace(/^\s*$/gm, '');
}

// Read all source files (order matters)
const wheel = fs.readFileSync('src/core/wheel.js', 'utf8');
const traversal = fs.readFileSync('src/core/traversal.js', 'utf8');
const navigation = fs.readFileSync('src/core/navigation.js', 'utf8');
const engine = fs.readFileSync('src/core/engine.js', 'utf8');
const handlers = fs.readFileSync('src/input/handlers.js', 'utf8');
const explorationMap = fs.readFileSync('src/ui/exploration-map.js', 'utf8');
const controller = fs.readFileSync('src/ui/controller.js', 'utf8');
const main = fs.readFileSync('src/main.js', 'utf8');

// Regular build (IIFE)
let bundled = `
// ═══════════════════════════════════════════════════════════════════════════════
// Drunk Walker v${VERSION} - Bundled Build
// ═══════════════════════════════════════════════════════════════════════════════
// ⚠️  AUTO-GENERATED FILE - DO NOT EDIT DIRECTLY!
//
// This file is generated by build.js from source files in src/
// Any changes made here will be LOST on next build.
//
// TO MAKE CHANGES:
//   Edit files in src/ directory, then run: node build.js
//   - src/core/wheel.js       - Wheel component
//   - src/core/traversal.js   - Traversal algorithms
//   - src/core/navigation.js  - Compatibility layer
//   - src/core/engine.js      - Core engine (state, timing, path recording)
//   - src/input/handlers.js   - Keyboard/mouse events
//   - src/ui/controller.js    - Control panel UI
//   - src/main.js             - Entry point
// ═══════════════════════════════════════════════════════════════════════════════
// Generated automatically by build.js
// Paste this entire code into browser console on Google Street View
// NOTE: If you see "Allow pasting?" warning, type: allow pasting

(function(){
  if (window.DRUNK_WALKER_ACTIVE) return;
  window.DRUNK_WALKER_ACTIVE = true;

  // === WHEEL ===
  ${stripModuleSyntax(wheel)}


  // === TRAVERSAL ALGORITHMS ===
  ${stripModuleSyntax(traversal)}

  // === NAVIGATION COMPATIBILITY LAYER ===
  ${stripModuleSyntax(navigation)}

  // === CORE ENGINE ===
  // State management, tick timing, path recording
  // TO CHANGE ENGINE: Edit src/core/engine.js
  ${stripModuleSyntax(engine)}

  // === INPUT HANDLERS ===
  ${stripModuleSyntax(handlers)}

  // === EXPLORATION MAP ===
  // Real-time mini-map showing explored territory
  ${stripModuleSyntax(explorationMap)}

  // === UI CONTROLLER ===
  ${stripModuleSyntax(controller)}

  // === MAIN ENTRY ===
  ${stripModuleSyntax(main)}
})();
`.trim();

// Console-friendly build (no outer IIFE, uses void operator)
let consoleFriendly = `
// ═══════════════════════════════════════════════════════════════════════════════
// Drunk Walker v${VERSION} - CONSOLE VERSION
// ═══════════════════════════════════════════════════════════════════════════════
// ⚠️  AUTO-GENERATED FILE - DO NOT EDIT DIRECTLY!
//
// This file is generated by build.js from source files in src/
// Any changes made here will be LOST on next build.
//
// TO MAKE CHANGES:
//   Edit files in src/ directory, then run: node build.js
//   - src/core/wheel.js       - Wheel component
//   - src/core/traversal.js   - Traversal algorithms
//   - src/core/navigation.js  - Compatibility layer
//   - src/core/engine.js      - Core engine (state, timing, path recording)
//   - src/input/handlers.js   - Keyboard/mouse events
//   - src/ui/controller.js    - Control panel UI
//   - src/ui/exploration-map.js - Exploration map component
//   - src/main.js             - Entry point
// ═══════════════════════════════════════════════════════════════════════════════
// This version is optimized for pasting into browser console
// 1. Type: allow pasting
// 2. Paste this code
// 3. Press Enter

void function initDrunkWalker(){
  if (window.DRUNK_WALKER_ACTIVE) {
    console.log('🤪 Drunk Walker already running. Refresh page to restart.');
    return;
  }
  window.DRUNK_WALKER_ACTIVE = true;

  // === WHEEL ===
  ${stripModuleSyntax(wheel)}


  // === TRAVERSAL ALGORITHMS ===
  ${stripModuleSyntax(traversal)}

  // === NAVIGATION COMPATIBILITY LAYER ===
  ${stripModuleSyntax(navigation)}

  // === CORE ENGINE ===
  // State management, tick timing, path recording
  // TO CHANGE ENGINE: Edit src/core/engine.js
  ${stripModuleSyntax(engine)}

  // === INPUT HANDLERS ===
  ${stripModuleSyntax(handlers)}

  // === EXPLORATION MAP ===
  // Real-time mini-map showing explored territory
  ${stripModuleSyntax(explorationMap)}

  // === UI CONTROLLER ===
  ${stripModuleSyntax(controller)}

  // === MAIN ENTRY ===
  ${stripModuleSyntax(main)}
}();
`.trim();



fs.writeFileSync(outfile, bundled);
fs.writeFileSync(consoleFile, consoleFriendly);

console.log(`✓ Built ${outfile} (${(bundled.length / 1024).toFixed(1)} KB)`);
console.log(`✓ Built ${consoleFile} (${(consoleFriendly.length / 1024).toFixed(1)} KB)`);
console.log(`\n📋 For browser console, use ${consoleFile} - it's more reliable for pasting!`);
